package com.dataprocessing.grpc;

import com.google.protobuf.ByteString;
import io.grpc.ManagedChannel;
import io.grpc.ManagedChannelBuilder;
import io.grpc.netty.shaded.io.grpc.netty.NettyChannelBuilder;
import io.grpc.stub.StreamObserver;
import java.io.*;
import java.nio.file.*;
import java.util.UUID;
import java.util.concurrent.CountDownLatch;
import java.util.concurrent.TimeUnit;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class FileServiceClient {

    private static final Logger logger = LoggerFactory.getLogger(FileServiceClient.class);
    private static final int MAX_MESSAGE_SIZE = Integer.MAX_VALUE;

    private final ManagedChannel channel;
    private final FileServiceGrpc.FileServiceStub asyncStub;
    private final FileServiceGrpc.FileServiceBlockingStub blockingStub;

    public FileServiceClient(String host, int port) {
        channel = NettyChannelBuilder.forAddress(host, port)
            .usePlaintext()
            .maxInboundMessageSize(MAX_MESSAGE_SIZE)
            .keepAliveTime(30, TimeUnit.SECONDS)
            .keepAliveTimeout(10, TimeUnit.SECONDS)
            .keepAliveWithoutCalls(true)
            .build();

        asyncStub = FileServiceGrpc.newStub(channel);
        blockingStub = FileServiceGrpc.newBlockingStub(channel);
    }

    public void uploadFile(String filePath) throws InterruptedException, IOException {
        CountDownLatch finishLatch = new CountDownLatch(1);
        Path path = Paths.get(filePath);
        String filename = path.getFileName().toString();
        long fileSize = Files.size(path);

        StreamObserver<UploadStatus> responseObserver = new StreamObserver<UploadStatus>() {
            @Override
            public void onNext(UploadStatus status) {
                logger.info("Upload response: success={}, message={}, bytesReceived={}, fileId={}",
                    status.getSuccess(), status.getMessage(),
                    status.getBytesReceived(), status.getFileId());
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Upload failed", t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Upload stream completed");
                finishLatch.countDown();
            }
        };

        StreamObserver<FileChunk> requestObserver = asyncStub.uploadFile(responseObserver);

        try (InputStream inputStream = new BufferedInputStream(new FileInputStream(path.toFile()))) {
            int chunkSize = 1024 * 1024; // 1MB chunks
            byte[] buffer = new byte[chunkSize];
            int bytesRead;
            long offset = 0;

            while ((bytesRead = inputStream.read(buffer)) != -1) {
                FileChunk chunk = FileChunk.newBuilder()
                    .setFilename(filename)
                    .setContent(ByteString.copyFrom(buffer, 0, bytesRead))
                    .setOffset(offset)
                    .setTotalSize(fileSize)
                    .build();

                requestObserver.onNext(chunk);
                offset += bytesRead;

                logger.debug("Sent chunk: offset={}, bytes={}", offset, bytesRead);
            }
        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        }

        requestObserver.onCompleted();

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warn("Upload did not complete within timeout");
        }
    }

    public void downloadFile(String filename, String outputPath) throws InterruptedException {
        CountDownLatch finishLatch = new CountDownLatch(1);

        FileRequest request = FileRequest.newBuilder()
            .setFilename(filename)
            .build();

        asyncStub.downloadFile(request, new StreamObserver<FileChunk>() {
            private OutputStream outputStream;

            @Override
            public void onNext(FileChunk chunk) {
                try {
                    if (outputStream == null) {
                        outputStream = new BufferedOutputStream(
                            new FileOutputStream(outputPath));
                    }
                    byte[] data = chunk.getContent().toByteArray();
                    outputStream.write(data);
                    logger.debug("Received download chunk: offset={}, bytes={}",
                        chunk.getOffset(), data.length);
                } catch (IOException e) {
                    logger.error("Error writing downloaded chunk", e);
                    onError(e);
                }
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Download failed", t);
                closeStream();
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Download completed: {}", outputPath);
                closeStream();
                finishLatch.countDown();
            }

            private void closeStream() {
                if (outputStream != null) {
                    try {
                        outputStream.flush();
                        outputStream.close();
                    } catch (IOException e) {
                        logger.error("Error closing output stream", e);
                    }
                }
            }
        });

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warn("Download did not complete within timeout");
        }
    }

    public void processDataBidirectional(java.util.List<byte[]> payloads, String contentType)
            throws InterruptedException {
        CountDownLatch finishLatch = new CountDownLatch(1);

        StreamObserver<DataMessage> responseObserver = new StreamObserver<DataMessage>() {
            @Override
            public void onNext(DataMessage response) {
                logger.info("Received processed data: messageId={}, contentType={}, payloadSize={}, headers={}",
                    response.getMessageId(),
                    response.getContentType(),
                    response.getPayload().size(),
                    response.getHeadersMap());
            }

            @Override
            public void onError(Throwable t) {
                logger.error("Bidirectional stream error", t);
                finishLatch.countDown();
            }

            @Override
            public void onCompleted() {
                logger.info("Bidirectional stream completed");
                finishLatch.countDown();
            }
        };

        StreamObserver<DataMessage> requestObserver = asyncStub.processData(responseObserver);

        try {
            for (byte[] payload : payloads) {
                DataMessage message = DataMessage.newBuilder()
                    .setMessageId(UUID.randomUUID().toString())
                    .setPayload(ByteString.copyFrom(payload))
                    .setContentType(contentType)
                    .putHeaders("source", "data-processing-client")
                    .setTimestamp(System.currentTimeMillis())
                    .build();

                requestObserver.onNext(message);
                logger.debug("Sent data message: id={}, size={}",
                    message.getMessageId(), payload.length);

                // Small delay to avoid overwhelming the server
                Thread.sleep(10);
            }
        } catch (RuntimeException e) {
            requestObserver.onError(e);
            throw e;
        }

        requestObserver.onCompleted();

        if (!finishLatch.await(5, TimeUnit.MINUTES)) {
            logger.warn("Bidirectional processing did not complete within timeout");
        }
    }

    public void shutdown() throws InterruptedException {
        channel.shutdown().awaitTermination(5, TimeUnit.SECONDS);
    }

    public static void main(String[] args) throws Exception {
        FileServiceClient client = new FileServiceClient("localhost", 9090);

        try {
            // Example: Upload a file
            if (args.length > 0 && "upload".equals(args[0])) {
                String filePath = args[1];
                client.uploadFile(filePath);
            }

            // Example: Download a file
            if (args.length > 0 && "download".equals(args[0])) {
                String filename = args[1];
                String outputPath = args.length > 2 ? args[2] : "./downloaded_" + filename;
                client.downloadFile(filename, outputPath);
            }

            // Example: Bidirectional data processing
            if (args.length > 0 && "process".equals(args[0])) {
                java.util.List<byte[]> payloads = new java.util.ArrayList<>();
                for (int i = 0; i < 10; i++) {
                    byte[] data = ("Sample data payload " + i).getBytes();
                    payloads.add(data);
                }
                client.processDataBidirectional(payloads, "application/octet-stream");
            }

        } finally {
            client.shutdown();
        }
    }
}


